-- ----------------------------
-- Table structure for bill_category
-- ----------------------------
DROP TABLE IF EXISTS `bill_category`;
CREATE TABLE `bill_category`  (
  `id` varchar(19) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '主键ID（雪花算法）',
  `category_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '分类名称',
  `category_type` tinyint(1) NOT NULL COMMENT '分类类型：1-收入，2-支出',
  `icon` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '图标',
  `sort_order` int NULL DEFAULT 0 COMMENT '排序',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `created` datetime NOT NULL COMMENT '创建时间',
  `last_upd` datetime NOT NULL COMMENT '修改时间',
  `created_by` varchar(19) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '创建者ID',
  `last_upd_by` varchar(19) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '修改者ID',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_category_type`(`category_type` ASC) USING BTREE,
  INDEX `idx_create_user_id`(`created_by` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '账单分类表' ROW_FORMAT = DYNAMIC;

