DROP TABLE IF EXISTS `bill_record`;
CREATE TABLE `bill_record`  (
  `id` varchar(19) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '主键ID（雪花算法）',
  `user_id` varchar(19) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '用户ID',
  `amount` decimal(10, 2) NOT NULL COMMENT '金额',
  `bill_type` tinyint(1) NOT NULL COMMENT '账单类型：1-收入，2-支出',
  `category_id` varchar(19) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '分类ID',
  `payment` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '支付方式',
  `bill_time` datetime NOT NULL COMMENT '账单时间（可手动选择，不选则=创建时间）',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `created` datetime NOT NULL COMMENT '创建时间',
  `last_upd` datetime NOT NULL COMMENT '修改时间',
  `created_by` varchar(19) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '创建者ID',
  `last_upd_by` varchar(19) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '修改者ID',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_bill_type`(`bill_type` ASC) USING BTREE,
  INDEX `idx_category_id`(`category_id` ASC) USING BTREE,
  INDEX `idx_account_id`(`payment` ASC) USING BTREE,
  INDEX `idx_bill_time`(`bill_time` ASC) USING BTREE,
  INDEX `idx_create_time`(`created` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '账单记录表' ROW_FORMAT = DYNAMIC;

