-- ----------------------------
-- Table structure for television_record
-- ----------------------------
DROP TABLE IF EXISTS `television_record`;
CREATE TABLE `television_record`  (
  `id` varchar(19) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '主键ID',
  `name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '剧名',
  `episode` int NULL DEFAULT 0 COMMENT '集数',
  `watch_status` int NOT NULL DEFAULT 0 COMMENT '观看状态：0-未开始，1-正在追，2-已结束',
  `rating` decimal(3, 1) NULL DEFAULT NULL COMMENT '评分(1-10分，带有一位小数点)',
  `category_id` varchar(19) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '分类ID',
  `start_time` datetime NULL DEFAULT NULL COMMENT '开始观看时间',
  `end_time` datetime NULL DEFAULT NULL COMMENT '结束观看时间',
  `remark` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `created` datetime NOT NULL COMMENT '创建时间',
  `last_upd` datetime NOT NULL COMMENT '修改时间',
  `created_by` varchar(19) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '创建者ID',
  `last_upd_by` varchar(19) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '修改者ID',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_name`(`name` ASC) USING BTREE,
  INDEX `idx_watch_status`(`watch_status` ASC) USING BTREE,
  INDEX `idx_category_id`(`category_id` ASC) USING BTREE,
  INDEX `idx_start_time`(`start_time` ASC) USING BTREE,
  INDEX `idx_end_time`(`end_time` ASC) USING BTREE,
  INDEX `idx_created_by`(`created_by` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '追剧记录表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of television_record
-- ----------------------------

